from django.db import models
from django.contrib.auth.models import User
from django.utils.translation import gettext_lazy as _
from dateutil.relativedelta import relativedelta

# ================================================================
# 1) جدول الشركات والفروع
# ================================================================
class SetupCompany(models.Model):
    # Company_ID is auto-generated by Django
    company_code = models.CharField(_('كود الشركة'), max_length=10, unique=True)
    company_name_ar = models.CharField(_('اسم الشركة (عربي)'), max_length=100)
    company_name_en = models.CharField(_('اسم الشركة (إنجليزي)'), max_length=100, null=True, blank=True)
    commercial_record = models.CharField(_('السجل التجاري'), max_length=50, null=True, blank=True)
    tax_number = models.CharField(_('الرقم الضريبي'), max_length=30, null=True, blank=True)
    phone1 = models.CharField(_('هاتف 1'), max_length=20, null=True, blank=True)
    phone2 = models.CharField(_('هاتف 2'), max_length=20, null=True, blank=True)
    email = models.EmailField(_('البريد الإلكتروني'), max_length=100, null=True, blank=True)
    website = models.URLField(_('الموقع الإلكتروني'), max_length=100, null=True, blank=True)
    country = models.CharField(_('الدولة'), max_length=50, null=True, blank=True)
    governorate = models.CharField(_('المحافظة'), max_length=50, null=True, blank=True)
    city = models.CharField(_('المدينة'), max_length=50, null=True, blank=True)
    district = models.CharField(_('الحي'), max_length=50, null=True, blank=True)
    street = models.CharField(_('الشارع'), max_length=100, null=True, blank=True)
    building_no = models.CharField(_('رقم المبنى'), max_length=20, null=True, blank=True)
    logo = models.ImageField(_('الشعار'), upload_to='company_logos/', null=True, blank=True) # Changed VARBINARY(MAX) to ImageField
    is_active = models.BooleanField(_('نشط'), default=True)
    
    # Tracking fields (Using Django's built-in User for Created_By/Modified_By)
    created_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, related_name='companies_created')
    created_date = models.DateTimeField(auto_now_add=True)
    modified_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, blank=True, related_name='companies_modified')
    modified_date = models.DateTimeField(auto_now=True, null=True, blank=True)

    class Meta:
        verbose_name = _('شركة')
        verbose_name_plural = _('الشركات')
        db_table = 'Setup_Company'

    def __str__(self):
        return self.company_name_ar

# ================================================================
# 4) جدول الموظفين الأساسي (مقدم على الأقسام والوظائف لحل مشكلة التبعية الدائرية)
# ================================================================
class HREmployee(models.Model):
    GENDER_CHOICES = [
        ('M', _('ذكر')),
        ('F', _('أنثى')),
    ]
    MARITAL_STATUS_CHOICES = [
        ('Single', _('أعزب')),
        ('Married', _('متزوج')),
        ('Divorced', _('مطلق')),
        ('Widowed', _('أرمل')),
    ]

    emp_code = models.CharField(_('كود الموظف'), max_length=20, unique=True)
    user = models.OneToOneField(User, on_delete=models.SET_NULL, null=True, blank=True, verbose_name=_('حساب المستخدم')) # Linking to Django User
    
    # Arabic Names
    first_name_ar = models.CharField(_('الاسم الأول (عربي)'), max_length=50)
    second_name_ar = models.CharField(_('الاسم الثاني (عربي)'), max_length=50)
    third_name_ar = models.CharField(_('الاسم الثالث (عربي)'), max_length=50, null=True, blank=True)
    last_name_ar = models.CharField(_('الاسم الأخير (عربي)'), max_length=50)

    # English Names
    first_name_en = models.CharField(_('الاسم الأول (إنجليزي)'), max_length=50, null=True, blank=True)
    second_name_en = models.CharField(_('الاسم الثاني (إنجليزي)'), max_length=50, null=True, blank=True)
    third_name_en = models.CharField(_('الاسم الثالث (إنجليزي)'), max_length=50, null=True, blank=True)
    last_name_en = models.CharField(_('الاسم الأخير (إنجليزي)'), max_length=50, null=True, blank=True)

    date_birth = models.DateField(_('تاريخ الميلاد'), null=True, blank=True)
    gender = models.CharField(_('النوع'), max_length=1, choices=GENDER_CHOICES, null=True, blank=True)
    nationality = models.CharField(_('الجنسية'), max_length=50, null=True, blank=True)
    national_id = models.CharField(_('الرقم القومي'), max_length=14, null=True, blank=True, db_index=True) # Added db_index for IX_Emp_NationalID
    personal_id_expiry = models.DateField(_('تاريخ انتهاء الهوية'), null=True, blank=True)
    marital_status = models.CharField(_('الحالة الاجتماعية'), max_length=30, choices=MARITAL_STATUS_CHOICES, null=True, blank=True)
    military_status = models.CharField(_('الحالة العسكرية'), max_length=30, null=True, blank=True)
    
    # Contact Info
    phone1 = models.CharField(_('هاتف 1'), max_length=20, null=True, blank=True)
    phone2 = models.CharField(_('هاتف 2'), max_length=20, null=True, blank=True)
    email_personal = models.EmailField(_('البريد الشخصي'), max_length=100, null=True, blank=True)
    email_official = models.EmailField(_('البريد الرسمي'), max_length=100, null=True, blank=True)
    
    # Address
    address_country = models.CharField(_('دولة العنوان'), max_length=50, null=True, blank=True)
    address_governorate = models.CharField(_('محافظة العنوان'), max_length=50, null=True, blank=True)
    address_city = models.CharField(_('مدينة العنوان'), max_length=50, null=True, blank=True)
    address_street = models.CharField(_('شارع العنوان'), max_length=200, null=True, blank=True)
    
    # Emergency
    emergency_contact = models.CharField(_('جهة اتصال للطوارئ'), max_length=100, null=True, blank=True)
    emergency_phone = models.CharField(_('هاتف الطوارئ'), max_length=20, null=True, blank=True)
    
    has_special_needs = models.BooleanField(_('ذوي الاحتياجات الخاصة'), default=False)
    notes = models.TextField(_('ملاحظات'), max_length=500, null=True, blank=True)
    is_active = models.BooleanField(_('نشط'), default=True)

    # Tracking fields
    created_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, related_name='employees_created')
    created_date = models.DateTimeField(auto_now_add=True)
    modified_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, blank=True, related_name='employees_modified')
    modified_date = models.DateTimeField(auto_now=True, null=True, blank=True)

    class Meta:
        verbose_name = _('موظف')
        verbose_name_plural = _('الموظفين')
        db_table = 'HR_Employee'

    @property
    def full_name_ar(self):
        # Computed column logic
        name = f"{self.first_name_ar} {self.second_name_ar}"
        if self.third_name_ar:
            name += f" {self.third_name_ar}"
        name += f" {self.last_name_ar}"
        return name.strip()

    @property
    def full_name_en(self):
        # Computed column logic
        name = f"{self.first_name_en or ''} {self.second_name_en or ''}"
        if self.third_name_en:
            name += f" {self.third_name_en}"
        name += f" {self.last_name_en or ''}"
        return name.strip()

    def __str__(self):
        return f"{self.emp_code} - {self.full_name_ar}"

# ================================================================
# 2) جدول الأقسام الرئيسية والفرعية
# ================================================================
class SetupDepartment(models.Model):
    company = models.ForeignKey(SetupCompany, on_delete=models.CASCADE, verbose_name=_('الشركة'))
    parent_dept = models.ForeignKey('self', on_delete=models.SET_NULL, null=True, blank=True, verbose_name=_('القسم الرئيسي'))
    dept_code = models.CharField(_('كود القسم'), max_length=20)
    dept_name_ar = models.CharField(_('اسم القسم (عربي)'), max_length=100)
    dept_name_en = models.CharField(_('اسم القسم (إنجليزي)'), max_length=100, null=True, blank=True)
    manager_emp = models.ForeignKey(HREmployee, on_delete=models.SET_NULL, null=True, blank=True, related_name='managed_department', verbose_name=_('مدير القسم'))
    is_active = models.BooleanField(_('نشط'), default=True)

    # Tracking fields
    created_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, related_name='departments_created')
    created_date = models.DateTimeField(auto_now_add=True)
    modified_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, blank=True, related_name='departments_modified')
    modified_date = models.DateTimeField(auto_now=True, null=True, blank=True)

    class Meta:
        verbose_name = _('قسم')
        verbose_name_plural = _('الأقسام')
        unique_together = ('company', 'dept_code')
        db_table = 'Setup_Department'

    def __str__(self):
        return f"{self.dept_name_ar} ({self.company.company_name_ar})"

