# ================================================================
# 5) جدول تعيينات الموظفين (تاريخي)
# ================================================================
class HREmployeeAssignment(models.Model):
    EMPLOYMENT_TYPE_CHOICES = [
        ('Permanent', _('دائم')),
        ('Temporary', _('مؤقت')),
        ('Contract', _('عقد')),
        ('Internship', _('تدريب')),
        ('PartTime', _('دوام جزئي')),
    ]

    emp = models.ForeignKey(HREmployee, on_delete=models.CASCADE, verbose_name=_('الموظف'))
    company = models.ForeignKey(SetupCompany, on_delete=models.PROTECT, verbose_name=_('الشركة'))
    dept = models.ForeignKey(SetupDepartment, on_delete=models.PROTECT, verbose_name=_('القسم'))
    job = models.ForeignKey(SetupJob, on_delete=models.PROTECT, verbose_name=_('الوظيفة'))
    direct_manager = models.ForeignKey(HREmployee, on_delete=models.SET_NULL, null=True, blank=True, related_name='subordinates', verbose_name=_('المدير المباشر'))
    
    employment_type = models.CharField(_('نوع التوظيف'), max_length=30, choices=EMPLOYMENT_TYPE_CHOICES)
    hiring_date = models.DateField(_('تاريخ التعيين'))
    probation_months = models.IntegerField(_('أشهر التجربة'), default=3)
    
    contract_start = models.DateField(_('بداية العقد'), null=True, blank=True)
    contract_end = models.DateField(_('نهاية العقد'), null=True, blank=True)
    
    basic_salary = models.DecimalField(_('الراتب الأساسي'), max_digits=18, decimal_places=2)
    currency = models.CharField(_('العملة'), max_length=3, default='EGP')
    
    shift_type = models.CharField(_('نوع الوردية'), max_length=30, null=True, blank=True)
    current_week_shift = models.CharField(_('وردية الأسبوع الحالي'), max_length=50, null=True, blank=True)
    next_week_shift = models.CharField(_('وردية الأسبوع القادم'), max_length=50, null=True, blank=True)
    friday_operation = models.CharField(_('عمليات الجمعة'), max_length=50, null=True, blank=True)
    
    is_current = models.BooleanField(_('التعيين الحالي'), default=True)

    # Tracking fields
    created_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, related_name='assignments_created')
    created_date = models.DateTimeField(auto_now_add=True)
    modified_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, blank=True, related_name='assignments_modified')
    modified_date = models.DateTimeField(auto_now=True, null=True, blank=True)

    class Meta:
        verbose_name = _('تعيين موظف')
        verbose_name_plural = _('تعيينات الموظفين')
        db_table = 'HR_Employee_Assignment'

    @property
    def probation_end_date(self):
        # Computed column logic: DATEADD(MONTH,Probation_Months,Hiring_Date)
        return self.hiring_date + relativedelta(months=self.probation_months)

    def __str__(self):
        return f"{self.emp.full_name_ar} - {self.job.job_name_ar} ({'Current' if self.is_current else 'Past'})"

