# ================================================================
# 7) رصيد الإجازات السنوي للموظف
# ================================================================
class HREmpLeaveBalance(models.Model):
    emp = models.ForeignKey(HREmployee, on_delete=models.CASCADE, verbose_name=_('الموظف'))
    leave_type = models.ForeignKey(SetupLeaveType, on_delete=models.PROTECT, verbose_name=_('نوع الإجازة'))
    year = models.IntegerField(_('السنة'))
    opening_balance = models.IntegerField(_('الرصيد الافتتاحي'))
    consumed_days = models.IntegerField(_('الأيام المستهلكة'), default=0)
    carry_forward_days = models.IntegerField(_('أيام مرحلة'), default=0)

    # Tracking fields
    created_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, related_name='leave_balances_created')
    created_date = models.DateTimeField(auto_now_add=True)
    modified_by = models.ForeignKey(User, on_delete=models.SET_NULL, null=True, blank=True, related_name='leave_balances_modified')
    modified_date = models.DateTimeField(auto_now=True, null=True, blank=True)

    class Meta:
        verbose_name = _('رصيد إجازة')
        verbose_name_plural = _('أرصدة الإجازات')
        unique_together = ('emp', 'leave_type', 'year')
        db_table = 'HR_Emp_Leave_Balance'

    @property
    def remaining_balance(self):
        # Computed column logic: Opening_Balance - Consumed_Days
        return self.opening_balance - self.consumed_days

    def __str__(self):
        return f"{self.emp.full_name_ar} - {self.leave_type.leave_name_ar} ({self.year})"

