class HREmpSalaryComponent(models.Model):
    emp = models.ForeignKey(HREmployee, on_delete=models.CASCADE, verbose_name=_('الموظف'))
    payroll_item = models.ForeignKey(SetupPayrollItem, on_delete=models.PROTECT, verbose_name=_('عنصر الراتب'))
    amount = models.DecimalField(_('المبلغ'), max_digits=18, decimal_places=2)
